use chrono::{DateTime, Local};
use std::error::Error;
use std::fmt;

/// A single task in the task manager.
#[derive(Debug, Clone)]
pub struct Task {
    pub id: u32,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Local>>,
    pub tags: Vec<String>,
}

/// Errors that can occur when operating on the task manager.
#[derive(Debug)]
pub enum TaskManagerError {
    TaskNotFound(u32),
}

impl fmt::Display for TaskManagerError {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            TaskManagerError::TaskNotFound(id) => write!(f, "task with id {} not found", id),
        }
    }
}

impl Error for TaskManagerError {}

/// Manages a collection of tasks.
#[derive(Debug, Default)]
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u32,
}

impl TaskManager {
    /// Creates a new, empty task manager.
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a task and returns a reference to the newly created task.
    pub fn add_task(
        &mut self,
        title: impl Into<String>,
        due_date: Option<DateTime<Local>>,
        tags: Vec<String>,
    ) -> &Task {
        let task = Task {
            id: self.next_id,
            title: title.into(),
            completed: false,
            due_date,
            tags,
        };

        self.tasks.push(task);
        self.next_id += 1;

        self.tasks
            .last()
            .expect("task vector must contain the just-inserted task")
    }

    /// Marks a task as completed.
    pub fn complete_task(&mut self, task_id: u32) -> Result<(), TaskManagerError> {
        let task = self
            .tasks
            .iter_mut()
            .find(|task| task.id == task_id)
            .ok_or(TaskManagerError::TaskNotFound(task_id))?;

        task.completed = true;
        Ok(())
    }

    /// Returns all overdue and incomplete tasks.
    pub fn get_overdue(&self) -> Vec<&Task> {
        let now = Local::now();

        self.tasks
            .iter()
            .filter(|task| {
                task.due_date
                    .as_ref()
                    .is_some_and(|due_date| *due_date < now)
                    && !task.completed
            })
            .collect()
    }

    /// Returns all tasks.
    pub fn tasks(&self) -> &[Task] {
        &self.tasks
    }
}

fn main() {
    let mut manager = TaskManager::new();

    let due_date = Some(Local::now() - chrono::Duration::days(1));

    let task = manager.add_task(
        "Finish Rust conversion",
        due_date,
        vec!["rust".to_string(), "coding".to_string()],
    );

    println!("Added task: {:?}", task);

    match manager.complete_task(1) {
        Ok(()) => println!("Task 1 completed"),
        Err(e) => eprintln!("Error completing task: {}", e),
    }

    let overdue = manager.get_overdue();
    println!("Overdue tasks: {:?}", overdue);
}
```

## Notes on Rust choices
- `Option<DateTime<Local>>` maps naturally from Python’s `Optional[datetime]`.
- `Vec<String>` maps from `List[str]`.
- `complete_task` returns `Result<(), TaskManagerError>` instead of `bool`, which is more idiomatic for operations that can fail.
- `get_overdue` returns `Vec<&Task>` to avoid cloning tasks unnecessarily.
- `add_task` takes `impl Into<String>` for ergonomic string input.

