use chrono::{DateTime, Local};
use thiserror::Error;

/// Errors that can occur during task management operations.
#[derive(Debug, Error)]
pub enum TaskError {
    #[error("Task with id {0} not found")]
    NotFound(u32),

    #[error("Task title cannot be empty")]
    EmptyTitle,
}

/// A single task with metadata.
#[derive(Debug, Clone)]
pub struct Task {
    pub id: u32,
    pub title: String,
    pub completed: bool,
    pub due_date: Option<DateTime<Local>>,
    pub tags: Vec<String>,
}

impl Task {
    /// Returns true if the task is overdue (past due date and not completed).
    pub fn is_overdue(&self) -> bool {
        self.due_date
            .map(|due| due < Local::now() && !self.completed)
            .unwrap_or(false)
    }
}

/// Manages a collection of tasks.
#[derive(Debug, Default)]
pub struct TaskManager {
    tasks: Vec<Task>,
    next_id: u32,
}

impl TaskManager {
    pub fn new() -> Self {
        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a new task and returns a reference to it.
    ///
    /// # Errors
    /// Returns [`TaskError::EmptyTitle`] if the title is blank.
    pub fn add_task(
        &mut self,
        title: impl Into<String>,
        due_date: Option<DateTime<Local>>,
        tags: Vec<String>,
    ) -> Result<&Task, TaskError> {
        let title = title.into();

        if title.trim().is_empty() {
            return Err(TaskError::EmptyTitle);
        }

        let task = Task {
            id: self.next_id,
            title,
            completed: false,
            due_date,
            tags,
        };

        self.tasks.push(task);
        self.next_id += 1;

        // Safety: we just pushed, so last() is always Some
        Ok(self.tasks.last().expect("task was just inserted"))
    }

    /// Marks a task as completed.
    ///
    /// # Errors
    /// Returns [`TaskError::NotFound`] if no task with the given id exists.
    pub fn complete_task(&mut self, task_id: u32) -> Result<(), TaskError> {
        self.tasks
            .iter_mut()
            .find(|t| t.id == task_id)
            .map(|t| t.completed = true)
            .ok_or(TaskError::NotFound(task_id))
    }

    /// Returns references to all overdue, incomplete tasks.
    pub fn get_overdue(&self) -> Vec<&Task> {
        self.tasks.iter().filter(|t| t.is_overdue()).collect()
    }

    /// Returns a reference to a task by id.
    pub fn get_task(&self, task_id: u32) -> Option<&Task> {
        self.tasks.iter().find(|t| t.id == task_id)
    }

    /// Returns references to all tasks.
    pub fn all_tasks(&self) -> &[Task] {
        &self.tasks
    }
}

fn main() {
    let mut manager = TaskManager::new();

    // Add tasks using method chaining style
    let task1 = manager
        .add_task("Buy groceries", None, vec!["personal".to_string()])
        .expect("valid task");

    println!("Created: {} (id={})", task1.title, task1.id);

    let past_due: DateTime<Local> = "2020-01-01T00:00:00+00:00"
        .parse()
        .expect("valid date");

    let task2 = manager
        .add_task(
            "File taxes",
            Some(past_due),
            vec!["finance".to_string(), "urgent".to_string()],
        )
        .expect("valid task");

    println!("Created: {} (id={})", task2.title, task2.id);

    // Complete a task
    match manager.complete_task(1) {
        Ok(()) => println!("Task 1 marked complete"),
        Err(e) => eprintln!("Error: {e}"),
    }

    // Attempt to complete a non-existent task
    match manager.complete_task(99) {
        Ok(()) => println!("Task 99 marked complete"),
        Err(e) => eprintln!("Expected error: {e}"),
    }

    // Query overdue tasks
    let overdue = manager.get_overdue();
    println!("\nOverdue tasks ({}):", overdue.len());
    for task in overdue {
        println!(
            "  [{}] {} — due: {}",
            task.id,
            task.title,
            task.due_date
                .map(|d| d.to_rfc3339())
                .unwrap_or_else(|| "none".to_string())
        );
    }

    // Empty title validation
    match manager.add_task("   ", None, vec![]) {
        Ok(_) => println!("Unexpected success"),
        Err(e) => eprintln!("\nValidation error caught: {e}"),
    }
}
```

## Notable Differences from Python

| Python | Rust |
|---|---|
| `Optional[T]` | `Option<T>` |
| `bool` return from `complete_task` | `Result<(), TaskError>` — encodes *why* it failed |
| `@dataclass` | Manual struct + `#[derive(Debug, Clone)]` |
| `datetime.now()` | `Local::now()` via `chrono` |
| Bare `append` (infallible) | `add_task` returns `Result` for validation |
| Duck-typed `title: str` | `impl Into<String>` accepts `&str` or `String` |
| Mutable list iteration | `iter_mut().find()` — zero-cost, no copies |

