            id: self.next_id,
            title: title.into(),
            completed: false,
            due_date,
            tags: tags.unwrap_or_default(),
        };

        self.tasks.push(task.clone());
        self.next_id += 1;

        task
    }

    pub fn complete_task(&mut self, task_id: u32) -> bool {
        for task in &mut self.tasks {
            if task.id == task_id {
                task.completed = true;
                return true;
            }
        }
        false
    }

    pub fn get_overdue(&self) -> Vec<&Task> {
        let now = Utc::now();
        self.tasks
            .iter()
            .filter(|t| {
                t.due_date.is_some_and(|due| due < now) && !t.completed
            })
            .collect()
    }

    // Additional idiomatic methods
    pub fn get_task(&self, id: u32) -> Option<&Task> {
        self.tasks.iter().find(|t| t.id == id)
    }

    pub fn get_all_tasks(&self) -> &[Task] {
        &self.tasks
    }

    pub fn remove_task(&mut self, id: u32) -> bool {
        if let Some(pos) = self.tasks.iter().position(|t| t.id == id) {
            self.tasks.remove(pos);
            true
        } else {
            false
        }
    }
}

impl Task {
    pub fn is_overdue(&self) -> bool {
        self.due_date.is_some_and(|due| due < Utc::now()) && !self.completed
    }
}
