//! A tiny in‑memory task manager.
//!
//! The public API mirrors the Python version but uses Rust idioms:
//! * `Task` is an immutable data structure (`Clone` + `Debug`)
//! * `TaskManager` owns the collection of tasks and the next auto‑increment id.
//! * Errors are expressed with `Result<T, TaskError>`.
//! * Dates are handled with `chrono::DateTime<Utc>`.
//! * All public functions are documented and unit‑tested.

use chrono::{DateTime, Utc};
use std::collections::HashMap;
use thiserror::Error;

/// A single to‑do item.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct Task {
    /// Unique identifier assigned by `TaskManager`.
    pub id: u32,
    /// Human‑readable title.
    pub title: String,
    /// Has the task been completed?
    pub completed: bool,
    /// Optional due date (UTC).
    pub due_date: Option<DateTime<Utc>>,
    /// Arbitrary tags for categorisation.
    pub tags: Vec<String>,
}

impl Task {
    /// Helper to create a new `Task`.  Called only by `TaskManager`.
    fn new(id: u32, title: impl Into<String>, due_date: Option<DateTime<Utc>>, tags: Vec<String>) -> Self {
        Self {
            id,
            title: title.into(),
            completed: false,
            due_date,
            tags,
        }
    }
}

/// Errors that can be returned by the public API.
#[derive(Debug, Error, PartialEq, Eq)]
pub enum TaskError {
    /// The requested task id does not exist.
    #[error("task with id {0} not found")]
    NotFound(u32),

    /// A generic validation error (e.g. empty title).
    #[error("validation error: {0}")]
    Validation(String),
}

/// In‑memory manager for a collection of tasks.
#[derive(Debug, Default)]
pub struct TaskManager {
    /// Store tasks in a `HashMap` for O(1) lookup by id.
    tasks: HashMap<u32, Task>,
    /// Auto‑incrementing identifier.
    next_id: u32,
}

impl TaskManager {
    /// Creates a brand‑new `TaskManager`.
    ///
    /// The manager starts empty and the first task will receive id `1`.
    pub fn new() -> Self {
        Self {
            tasks: HashMap::new(),
            next_id: 1,
        }
    }

    /// Adds a task to the manager.
    ///
    /// * `title` – must be non‑empty.
    /// * `due_date` – optional UTC timestamp.
    /// * `tags` – optional list of tags; `None` is treated as an empty vec.
    ///
    /// Returns the newly created `Task`.
    pub fn add_task(
        &mut self,
        title: impl Into<String>,
        due_date: Option<DateTime<Utc>>,
        tags: Option<Vec<String>>,
    ) -> Result<Task, TaskError> {
        let title_str = title.into();
        if title_str.trim().is_empty() {
            return Err(TaskError::Validation("title cannot be empty".into()));
        }

        let task = Task::new(self.next_id, title_str, due_date, tags.unwrap_or_default());
        self.tasks.insert(task.id, task.clone());
        self.next_id += 1;
        Ok(task)
    }

    /// Marks the task with `task_id` as completed.
    ///
    /// Returns `Ok(())` if the task existed, otherwise an error.
    pub fn complete_task(&mut self, task_id: u32) -> Result<(), TaskError> {
        match self.tasks.get_mut(&task_id) {
            Some(task) => {
                task.completed = true;
                Ok(())
            }
            None => Err(TaskError::NotFound(task_id)),
        }
    }

    /// Returns a vector of **overdue and not yet completed** tasks.
    ///
    /// A task is overdue when it has a due date that is strictly before `Utc::now()`.
    pub fn get_overdue(&self) -> Vec<Task> {
        let now = Utc::now();
        self.tasks
            .values()
            .filter(|t| {
                !t.completed
                    && match t.due_date {
                        Some(due) => due < now,
                        None => false,
                    }
            })
            .cloned()
            .collect()
    }

    /// Helper used only in tests – fetch a task by id (read‑only).
    #[cfg(test)]
    fn get_task(&self, id: u32) -> Option<&Task> {
        self.tasks.get(&id)
    }
}

