        Self {
            tasks: Vec::new(),
            next_id: 1,
        }
    }

    /// Adds a new task.
    /// Returns a reference to the created task.
    /// Note: In a real app, we might return `Result` for allocation errors.
    pub fn add_task(
        &mut self,
        title: String,
        due_date: Option<NaiveDateTime>,
        tags: Vec<String>,
    ) -> &Task {
        let task = Task::new(self.next_id, title, due_date, tags);

        // We need to increment the ID. 
        // In a production system, we might handle overflow with `checked_add`.
        self.next_id += 1;

        self.tasks.push(task);

        // Return a reference to the newly added task
        self.tasks.last().unwrap()
    }

    /// Marks a task as completed by ID.
    /// Returns true if the task was found, false otherwise.
    /// Takes &mut self because we are modifying the internal state.
    pub fn complete_task(&mut self, task_id: u64) -> bool {
        // We use iter_mut to get exclusive access to the tasks
        for task in self.tasks.iter_mut() {
            if task.id == task_id {
                task.completed = true;
                return true;
            }
        }
        false
    }

    /// Returns a list of tasks that are overdue and not completed.
    /// This returns a new Vec containing cloned data to avoid lifetime issues
    /// with borrowing self while iterating.
    pub fn get_overdue(&self) -> Vec<Task> {
        let now = Utc::now().naive_utc(); // Get current time as NaiveDateTime

        self.tasks
            .iter()
            // Filter: Must have a due date, due date is before now, and not completed
            .filter(|t| {
                t.due_date
                    .map(|due| due < now && !t.completed)
                    .unwrap_or(false)
            })
            // We must clone to return owned data
            .cloned()
            .collect()
    }
}

